import React from "react";
import '../styles/Contact.css'

const Contact = () => {
  return (
    <div className="Contact">
      <h2>Contact Us</h2>
      <p>Email: contact@lawfirm.com | Phone: +123 456 789</p>
    </div>
  );
};

export default Contact;
